import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.next();

        // Validate input length against buffer size
        char[] buffer = new char[10];

        int copyLength = Math.min(userInput.length(), buffer.length);

        for (int i = 0; i < copyLength; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Input successfully stored in buffer: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
